SELECT COUNT(1)
FROM building_unit
WHERE building_id = #{buildingId}
  AND name = #{name}
  AND deleted = 0

  AND id != #{excludeId}

SELECT
FROM building_unit WHERE deleted = 0
AND building_id = #{buildingId}
AND name LIKE CONCAT('%', #{name}, '%')
AND status = #{status}
ORDER BY sort_no ASC, id ASC
